import{_ as t,a as r}from"./chunks/dgrid-openclaw-demo.Rr2R33J3.js";import{_ as a,c as o,o as i,ag as n}from"./chunks/framework.S-Qvb3wi.js";const b=JSON.parse('{"title":"AI Gateway Integration Tutorials","description":"","frontmatter":{},"headers":[],"relativePath":"AI-Gateway-Integrations.md","filePath":"AI-Gateway-Integrations.md"}'),l={name:"AI-Gateway-Integrations.md"};function s(d,e,g,p,h,u){return i(),o("div",null,e[0]||(e[0]=[n('<h1 id="ai-gateway-integration-tutorials" tabindex="-1">AI Gateway Integration Tutorials <a class="header-anchor" href="#ai-gateway-integration-tutorials" aria-label="Permalink to &quot;AI Gateway Integration Tutorials&quot;">​</a></h1><p>This page collects practical integration tutorials for using <strong>DGrid AI Gateway</strong> in common developer tools and SDKs.</p><h2 id="cursor-override-openai-base-url" tabindex="-1">Cursor (Override OpenAI Base URL) <a class="header-anchor" href="#cursor-override-openai-base-url" aria-label="Permalink to &quot;Cursor (Override OpenAI Base URL)&quot;">​</a></h2><ol><li>Get your <code>DGRID_API_KEY</code> (see the prerequisite in <a href="/AI-Gateway">AI Gateway</a>).</li><li>Open <strong>Cursor Settings</strong> → <strong>Models</strong>.</li><li>Under <strong>API Keys</strong>, enable <strong>Override OpenAI Base URL</strong>.</li><li>Set the base URL to: <ul><li><code>https://api.dgrid.ai/v1</code></li></ul></li><li>Paste your <code>DGRID_API_KEY</code> into <strong>OpenAI API Key</strong>.</li><li>Pick any supported model name using the DGrid format (for example: <code>openai/gpt-4o</code>).</li></ol><p><img src="'+t+'" alt="Cursor settings example"></p><p>Full tutorial: <a href="https://blog.dgrid.ai/posts/2026-02-18/" target="_blank" rel="noreferrer">How to Configure and Use DGrid AI Gateway in Cursor</a></p><h2 id="openai-sdk-node-js-python" tabindex="-1">OpenAI SDK (Node.js / Python) <a class="header-anchor" href="#openai-sdk-node-js-python" aria-label="Permalink to &quot;OpenAI SDK (Node.js / Python)&quot;">​</a></h2><ul><li>See: <a href="/AI-Gateway#quickstart">AI Gateway Quickstart</a></li></ul><h2 id="openclaw" tabindex="-1">OpenClaw <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw&quot;">​</a></h2><p>You can configure OpenClaw to route requests through <strong>DGrid AI Gateway</strong> using the OpenAI-compatible endpoint.</p><ol><li>Open your OpenClaw model/provider settings.</li><li>Set the API base URL to <code>https://api.dgrid.ai/v1</code>.</li><li>Paste your <code>DGRID_API_KEY</code> into the API key field.</li><li>Select a supported DGrid model ID.</li><li>Save the configuration and run a quick test request.</li></ol><video controls preload="metadata" style="width:100%;border-radius:12px;margin-top:12px;"><source src="'+r+'" type="video/mp4"> Your browser does not support the video tag. </video><h2 id="blog-integration-tutorials-collected" tabindex="-1">Blog integration tutorials (collected) <a class="header-anchor" href="#blog-integration-tutorials-collected" aria-label="Permalink to &quot;Blog integration tutorials (collected)&quot;">​</a></h2><ul><li><strong>AI as Workspace (AIaW)</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-10/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in AI as Workspace (AIaW)</a></li><li><strong>AnythingLLM</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-30/" target="_blank" rel="noreferrer">Tutorial: Using DGrid AI Gateway with AnythingLLM</a></li><li><strong>Chatbox</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-09/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in Chatbox</a></li><li><strong>Claude Code</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-12/" target="_blank" rel="noreferrer">Use Claude Code with DGrid</a></li><li><strong>Codex CLI</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-23/" target="_blank" rel="noreferrer">Using Codex CLI with DGrid: A Complete Guide</a></li><li><strong>LibreChat</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-28/" target="_blank" rel="noreferrer">Using DGrid with LibreChat: A Step-by-Step Guide</a></li><li><strong>LobeChat</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-09/" target="_blank" rel="noreferrer">Configuring and Utilizing DGrid AI Gateway in LobeChat: A Full Guide</a></li><li><strong>Open WebUI</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-22_2/" target="_blank" rel="noreferrer">Using DGrid AI Gateway with Open WebUI: A Comprehensive Guide</a></li><li><strong>OpenClaw (agent platform)</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-02/" target="_blank" rel="noreferrer">Supercharging OpenClaw with DGrid: The Ultimate AI Agent Setup</a></li><li><strong>OpenClaw (no-code)</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-27/" target="_blank" rel="noreferrer">Step-by-Step Guide: OpenClaw Installation &amp; DGrid AI Gateway Setup (No Code Required)</a></li><li><strong>Vercel AI SDK</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-26/" target="_blank" rel="noreferrer">How to Use DGrid AI Gateway with the Vercel AI SDK</a></li></ul>',14)]))}const A=a(l,[["render",s]]);export{b as __pageData,A as default};
